SELECT * FROM image_library WHERE status = 1

    AND image_name LIKE CONCAT('%', #{imageName}, '%')


    AND category = #{category}


    AND uploader_id = #{uploaderId}


    AND tags LIKE CONCAT('%', #{tags}, '%')

ORDER BY create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM image_library WHERE status = 1

    AND image_name LIKE CONCAT('%', #{imageName}, '%')


    AND category = #{category}


    AND uploader_id = #{uploaderId}


    AND tags LIKE CONCAT('%', #{tags}, '%')

SELECT * FROM image_library
WHERE status = 1
  AND reference_type = #{referenceType}
  AND reference_id = #{referenceId}
ORDER BY create_time DESC
